\u0069\u0049\u006d\u0061\u0052\u0058\u003b\u0051\u0065\u007a\u0042\u0052\u0059\u0049\u0057\u006e\u004e\u0056\u006b\u0050\u0046\u002c\u0021\u004d\u0038\u0026\u004d\u0055\u0032\u0028\u004b\u0035\u007b\u0075\u005f\u0040\u0062\u0068\u0021\u004d\u0074\u002f\u0044\u0074\u0059\u0049\u0034\u006f\u007c\u0044\u0063\u0056\u007a\u0065\u0046\u007c\u004b\u0032\u004e\u005e\u0022\u0046\u0071\u004e\u0022\u0062\u0053\u0069\u006a\u0058\u0062\u006c\u0054\u0051\u0025\u0074\u007c\u0068\u0042\u0045\u0030\u007d\u0062\u0050\u0052\u0028\u0061\u003d\u0029\u0042\u0079\u006f\u0055\u0074\u004b\u0035\u0077\u0054\u004a\u002b\u003d\u003f\u0068\u0031\u0036\u0042\u0030\u0060\u0077\u0049\u006e\u002a\u006b\u004e\u0054\u007b\u0062\u0068\u0049\u0030\u0033\u0042\u0041\u0055\u0039\u0033\u003a\u004e\u004c\u0068\u0021\u002c\u002f\u007a\u0061\u003d\u005a\u007a\u0025\u002a\u005a\u005d\u0030\u002b\u0033\u007c\u0062\u0050\u004d\u003d\u0032\u003d\u0047\u007a\u0025\u002a\u005e\u0033\u003f\u002b\u002e\u0054\u0037\u0035\u0025\u0047\u004f\u0051\u002b\u004b\u006c\u0060\u0049\u0049\u0025\u0037\u005d\u004d\u0071\u002b\u0062\u0068\u0021\u0055\u0074\u002f\u0044\u0074\u0077\u004b\u0063\u0033\u002c\u0068\u0068\u007b\u003f\u0065\u003c\u002b\u003d\u004c\u003b\u006f\u006f\u006d\u002a\u004e\u0057\u004b\u0052\u002c\u002f\u007a\u0032\u003d\u0047\u007a\u0025\u002a\u005e\u0033\u003f\u002b\u002e\u0054\u0037\u0035\u0025\u0047\u007b\u005f\u002a\u0078\u0050\u005f\u0048\u004b\u0050\u006f\u005d\u0053\u0067\u0035\u006d\u0042\u0078\u0069\u0047\u007a\u006b\u005e\u007a\u005d\u003d\u006f\u0030\u0049\u0068\u002b\u002f\u007a\u0038\u006c\u0051\u0063\u0050\u005f\u0046\u0049\u003a\u004e\u0057\u0059\u0067\u0035\u0037\u003f\u0055\u004d\u0038\u0026\u002e\u005f\u0059\u0049\u003a\u004e\u0022\u0075\u0067\u0035\u0039\u0036\u0055\u004d\u0065\u0070\u0050\u005f\u005f\u0066\u0074\u004e\u0068\u0068\u0054\u007b\u003f\u0065\u0046\u007c\u0059\u0032\u0074\u0073\u0069\u0049\u0078\u0035\u0061\u0075\u0067\u0035\u002f\u007a\u0043\u0033\u0036\u007a\u0061\u0076\u005e\u0033\u0037\u0045\u003a\u003d\u0067\u0035\u0039\u0036\u0055\u004d\u0036\u007a\u0050\u005f\u0059\u0049\u005f\u004e\u0061\u0075\u005f\u0040\u0062\u0068\u0048\u0055\u0079\u0049\u0062\u0055\u0028\u0047\u0035\u0062\u0022\u002c\u002b\u0035\u007c\u003f\u004a\u007c\u007e\u004b\u0040\u0071\u006b\u0074\u003a\u0076\u0047\u0053\u0070\u005e\u004b\u003d\u0040\u0078\u0065\u0071\u0056\u0048\u007c\u0039\u0067\u003d\u0022\u002c\u0067\u0064\u004d\u0047\u002c\u0078\u0037\u0063\u004a\u0071\u0030\u006d\u006b\u0035\u006b\u004e\u0026\u004d\u004b\u0065\u004d\u0031\u006b\u004b\u0053\u0021\u0077\u004b\u002a\u004e\u0022\u0075\u002e\u002c\u0039\u0036\u0041\u004d\u0036\u007a\u0050\u005f\u0059\u0049\u003a\u004e\u0022\u0075\u0067\u0035\u0039\u0036\u0055\u004d\u0036\u007a\u0024\u004c\u0061\u0033\u003f\u002b\u0025\u0051\u0049\u0064\u004c\u007a\u0043\u0028\u0029\u0042\u002e\u005f\u0032\u0028\u0066\u006f\u0061\u0075\u0046\u0035\u0079\u0078\u0073\u006e\u0075\u0047\u0050\u005f\u0059\u0049\u003a\u004e\u0022\u0075\u0067\u0035\u0039\u0036\u007b\u0035\u0023\u0021\u0052\u0074\u0064\u0068\u002b\u0067\u0053\u003b\u0079\u002a\u0056\u0042\u003f\u0031\u0043\u0051\u003f\u006f\u006a\u0049\u0040\u0037\u0059\u006b\u0056\u003f\u0054\u002c\u004e\u006e\u0047\u0042\u003b\u0071\u0048\u0045\u0054\u006b\u004e\u006d\u006a\u0055\u0064\u0069\u002a\u0043\u007d\u0032\u005e\u004f\u0065\u0024\u007a\u0054\u0033\u0044\u0033\u002b\u0072\u0036\u0034\u0037\u0036\u007a\u004b\u0070\u0064\u0068\u003d\u006f\u0079\u0075\u0047\u003b\u007c\u007a\u0052\u006f\u0056\u0042\u0048\u0023\u006b\u0047\u0064\u006f\u003b\u006e\u0066\u002e\u0057\u004b\u0057\u004e\u0036\u002f\u0038\u006f\u005a\u0047\u0053\u0044\u0025\u0031\u0022\u002c\u006f\u007a\u0024\u0028\u0047\u007a\u0022\u0048\u0032\u0028\u0038\u006e\u0055\u0062\u0049\u0021\u007d\u0058\u0041\u004d\u0063\u0046\u006a\u0063\u0077\u0075\u0036\u0066\u0043\u005e\u0079\u002c\u0029\u0065\u0037\u0052\u003d\u003f\u005f\u0029\u005e\u0051\u0079\u0076\u0047\u0076\u0077\u005a\u0039\u0036\u0035\u006f\u0055\u004c\u002e\u005a\u0045\u004c\u005f\u0062\u0057\u007e\u0031\u003f\u003b\u005a\u0056\u007b\u0075\u003f\u0051\u002a\u004c\u006a\u0029\u002b\u0063\u005b\u0037\u007b\u002f\u003f\u003b\u0033\u0068\u0051\u003a\u004a\u0049\u0022\u0040\u0062\u0022\u0075\u0043\u0023\u0069\u0069\u005a\u004c\u0062\u0048\u002a\u002a\u0022\u003b\u0046\u0035\u0034\u0022\u006c\u003b\u003e\u0078\u0049\u0074\u0031\u0078\u0053\u005a\u0063\u0050\u0036\u006b\u0050\u002a\u0030\u003f\u007d\u003f\u0072\u0034\u007a\u0079\u0061\u0021\u0067\u0049\u0029\u004e\u0053\u0055\u0048\u0068\u005e\u005a\u0047\u0030\u0069\u0042\u007d\u002b\u0048\u006d\u0043\u007c\u005a\u005b\u003e\u0064\u0039\u0040\u0064\u0030\u0042\u0043\u003a\u0029\u0042\u0022\u0042\u007d\u0028\u0053\u0077\u0061\u006f\u006d\u004b\u0028\u003a\u0079\u002e\u005a\u007d\u0022\u0078\u0076\u0032\u004e\u0024\u0035\u006e\u003d\u0034\u0052\u006f\u004c\u004e\u002a\u0049\u0058\u0048\u0052\u006c\u003d\u0068\u0024\u003c\u0040\u0038\u007a\u0031\u0032\u0039\u0063\u0041\u0051\u0066\u0052\u0034\u003f\u0022\u002a\u003a\u0078\u006b\u0028\u005f\u0053\u0037\u004f\u0021\u002f\u003d\u0043\u003c\u0026\u0022\u0055\u006c\u002c\u0067\u007b\u003e\u0042\u0059\u005b\u004e\u0074\u0038\u0067\u0049\u0024\u0072\u0035\u0032\u0073\u002a\u004d\u0068\u0060\u0039\u005a\u0046\u0046\u0040\u005d\u0061\u0061\u003d\u0040\u0052\u0058\u0035\u0060\u0053\u0046\u0048\u005b\u0026\u004f\u0044\u0049\u0058\u002f\u007a\u0024\u0053\u0078\u0071\u005f\u0030\u0032\u002a\u0079\u007e\u004c\u0053\u003d\u003e\u0032\u007c\u005e\u0046\u0066\u0062\u005f\u0022\u002f\u003c\u007b\u004f\u005d\u0038\u003d\u0039\u0037\u0050\u004f\u0056\u005d\u0044\u0035\u002b\u004b\u007a\u005a\u0075\u0058\u0057\u0076\u004f\u0022\u0054\u002a\u0049\u0066\u0057\u004c\u0022\u0078\u0062\u0048\u0046\u004c\u0047\u0048\u005b\u0056\u0045\u0061\u0066\u0037\u005d\u0033\u0072\u0060\u0059\u0044\u0055\u0041\u003c\u006b\u0041\u0045\u004e\u0077\u0065\u0034\u003e\u0069\u006c\u005e\u0044\u006b\u0039\u0076\u0046\u003d\u0024\u0070\u003e\u0064\u0028\u0066\u0046\u0076\u0026\u0060\u0022\u004f\u0044\u0024\u007e\u0033\u0035\u005b\u0031\u0056\u0052\u007a\u004c\u0078\u0075\u0052\u0069\u0070\u003b\u0048\u0036\u0066\u0064\u0069\u003d\u004f\u0064\u005d\u0077\u0055\u004d\u0079\u0079\u0021\u0066\u006d\u004d\u0052\u002c\u0055\u005b\u0035\u006d\u003d\u0072\u0076\u006a\u007b\u002a\u005b\u0066\u0048\u0034\u0066\u0073\u004d\u002f\u0037\u007e\u003d\u0038\u004d\u0034\u004c\u006e\u002a\u003d\u0049\u0071\u0048\u002f\u007d\u005e\u007b\u003e\u0078\u0033\u0032\u0052\u0044\u003b\u0032\u0067\u0058\u007e\u0052\u0051\u0031\u0073\u0035\u0055\u003f\u0067\u0026\u006f\u0051\u0048\u006b\u0050\u006d\u0031\u006f\u0052\u0062\u003b\u0029\u007c\u0034\u002b\u0078\u0060\u0052\u004b\u006a\u003c\u002f\u0049\u0041\u0045\u005d\u0064\u0029\u0066\u003f\u0075\u0060\u0051\u0042\u0022\u0022\u006c\u0031\u005e\u006b\u005f\u0071\u0023\u0055\u0045\u006c\u004e\u006e\u002b\u0078\u0023\u002f\u005a\u0064\u0065\u006b\u0054\u004c\u0021\u003b\u0032\u0073\u002c\u0032\u0076\u0056\u007b\u005b\u0059\u0066\u0074\u0045\u002c\u004c\u0066\u0021\u0057\u0040\u0072\u0070\u0079\u0032\u0071\u0044\u002f\u0028\u006e\u0037\u004a\u0037\u005f\u005e\u0052\u0058\u0069\u0030\u0031\u0021\u0029\u005e\u006c\u0028\u006b\u007c\u004f\u007d\u006d\u0064\u003e\u0028\u002c\u0052\u0039\u0043\u0054\u0034\u0054\u0074\u002a\u004e\u0031\u0079\u0022\u004f\u002f\u003f\u0047\u0030\u0060\u003f\u0050\u002f\u0053\u004f\u0077\u0066\u0070\u0079\u0075\u002c\u007b\u0066\u0076\u0035\u0059\u0021\u0052\u0079\u0040\u006b\u0059\u003b\u0047\u003f\u0058\u0056\u0065\u007a\u0050\u0069\u0065\u0070\u0054\u005a\u0050\u006d\u0076\u002b\u0070\u0032\u0054\u0024\u0065\u0037\u0057\u0048\u0044\u0051\u0021\u0069\u0049\u002c\u0036\u003b\u0060\u0071\u0033\u0023\u006f\u0058\u0043\u0069\u002c\u003e\u0043\u002a\u0064\u0068\u006d\u0052\u0060\u004e\u003d\u005e\u0028\u0066\u0031\u0052\u007a\u0053\u004b\u0029\u0063\u0066\u0040\u005d\u0065\u006e\u0056\u0073\u0071\u0078\u005e\u0076\u003a\u0079\u0056\u005e\u0024\u0045\u004e\u002f\u005d\u004c\u0044\u002e\u0040\u0028\u006d\u0031\u002f\u0048\u005d\u005a\u0071\u0032\u0043\u006e\u005e\u004a\u0068\u005e\u003e\u0078\u0071\u0076\u0030\u0026\u0066\u003e\u004d\u003b\u006d\u0041\u0062\u0062\u0021\u003b\u0041\u003d\u0069\u0032\u005b\u0070\u0036\u0063\u004a\u0033\u004c\u0041\u0043\u0055\u0037\u006b\u004b\u006d\u0077\u0054\u0063\u0047\u0021\u006b\u002a\u0032\u005d\u0052\u0046\u004a\u0040\u002b\u0039\u0028\u004a\u006e\u0024\u0056\u0037\u0076\u002b\u0024\u005a\u003b\u002a\u0056\u005a\u0022\u0072\u0034\u007d\u0031\u006b\u0048\u004b\u0077\u0044\u004b\u004c\u0033\u006c\u0055\u005e\u004d\u0033\u0078\u005e\u0069\u003f\u005e\u0070\u004f\u0034\u0068\u0046\u0067\u0051\u005b\u0042\u0064\u005a\u0069\u0067\u004b\u006e\u004c\u0023\u0077\u003f\u0048\u0034\u0045\u0028\u0070\u003e\u005a\u0034\u004f\u005a\u0032\u0040\u0052\u0078\u0052\u0040\u0041\u0076\u0033\u005d\u003b\u0023\u0024\u0023\u007a\u0031\u0052\u0037\u0052\u0028\u0031\u0036\u0074\u0040\u0033\u0049\u0064\u006c\u0060\u0070\u0073\u0053\u006f\u0070\u0026\u006c\u004e\u0030\u006d\u004e\u006e\u006e\u0054\u0024\u0064\u0041\u0069\u0063\u004b\u005a\u0044\u0022\u005b\u004d\u0058\u0032\u003d\u002f\u0070\u007b\u002b\u0068\u006d\u0056\u006f\u005e\u004d\u0057\u0024\u0031\u0047\u0026\u0045\u0040\u0047\u0040\u0037\u007d\u0028\u0045\u006e\u0048\u0042\u0053\u0071\u0024\u0066\u0023\u0041\u004c\u0061\u0023\u006d\u0072\u006c\u0021\u0078\u002f\u0053\u0052\u004e\u0063\u0058\u007d\u0066\u0040\u005e\u0041\u0055\u0037\u0078\u0070\u006c\u0040\u0060\u0028\u004a\u004e\u002f\u0072\u003b\u004e\u002b\u0076\u003b\u005f\u003f\u0025\u005d\u003b\u0044\u002c\u0077\u003a\u0068\u007d\u0052\u0067\u0055\u0047\u0059\u002a\u004b\u006b\u002b\u003e\u0043\u0074\u0079\u0046\u0049\u007e\u006f\u0046\u0060\u006c\u0069\u0055\u0073\u0032\u004e\u0039\u0070\u0061\u0021\u005b\u004b\u0029\u002b\u0044\u0070\u0057\u0022\u0031\u005d\u0043\u0078\u0077\u0059\u002e\u003e\u0066\u0066\u004a\u0045\u005b\u007e\u0029\u0056\u005e\u002c\u0049\u007b\u0043\u0047\u006b\u0061\u0051\u004f\u005d\u0045\u002c\u002f\u0075\u004f\u0070\u0073\u0067\u0045\u0057\u0026\u0048\u005e\u0054\u005d\u007c\u0066\u0032\u0067\u0056\u0073\u0068\u007a\u007e\u004e\u003a\u0079\u0031\u0034\u0028\u0041\u004d\u006f\u0063\u0071\u0034\u0061\u0061\u0069\u0067\u0065\u005b\u0060\u007a\u002b\u0052\u0039\u004a\u002a\u0077\u002a\u003c\u0077\u0041\u005d\u0060\u004c\u0073\u0047\u0068\u003e\u0023\u0068\u004e\u007c\u0040\u0031\u0046\u007b\u0043\u0066\u004a\u0034\u006b\u0026\u0024\u0047\u0074\u005d\u0062\u0037\u006b\u004a\u0070\u0060\u004e\u006c\u0053\u0031\u005b\u0051\u006a\u006a\u002e\u0068\u0064\u0037\u004f\u0055\u0065\u0078\u0069\u005d\u0040\u002a\u003c\u0052\u0021\u0031\u0065\u0050\u0053\u0076\u0028\u0070\u0042\u0035\u006c\u005a\u005b\u007a\u004c\u0026\u004d\u0076\u0058\u0066\u0077\u002a\u006a\u007e\u006c\u005a\u007d\u003f\u005b\u005f\u003d\u004c\u0036\u002f\u004b\u006f\u0066\u0043\u005f\u0044\u0038\u002c\u0065\u006d\u004f\u006f\u002a\u0044\u0078\u0052\u0074\u0047\u0055\u0048\u0068\u0068\u0065\u0064\u0070\u0073\u0058\u006e\u0052\u0049\u003f\u003e\u0051\u0047\u0043\u0076\u005e\u0067\u0043\u005e\u003f\u003d\u0070\u004e\u0077\u0026\u0063\u004a\u0063\u0049\u0053\u0076\u0034\u005b\u0064\u0029\u0030\u005a\u002c\u0028\u0037\u0071\u0072\u007b\u0039\u0032\u003f\u006e\u002b\u0026\u0075\u0040\u0037\u007c\u005d\u0028\u0043\u004c\u0059\u0034\u0037\u0049\u0044\u0049\u0043\u0052\u007a\u007b\u0050\u0073\u0041\u007a\u0068\u0052\u0066\u003e\u0043\u0048\u0066\u0052\u0037\u007c\u003c\u004d\u006e\u0068\u003c\u0070\u0022\u0021\u0040\u002f\u0071\u0033\u0042\u0048\u006c\u004d\u002b\u005a\u0045\u0069\u005d\u007b\u005a\u0044\u004f\u006a\u005f\u006f\u004b\u0076\u0046\u0079\u0066\u007b\u0075\u004f\u006c\u0078\u004a\u0051\u0053\u0071\u0039\u004a\u005d\u0052\u0074\u0070\u006b\u006b\u004a\u0073\u0076\u0055\u002a\u0078\u0052\u0061\u002e\u002f\u0066\u0052\u007d\u003d\u0051\u0059\u0070\u0042\u006a\u0051\u0046\u0026\u0049\u0039\u0032\u0051\u006b\u0035\u0047\u005b\u007c\u002b\u004c\u0034\u004b\u006e\u0073\u002f\u0023\u0021\u0065\u0075\u0026\u007d